class BSTIterator:
    def __init__(self, root):
        self.vals = []
        def dfs(node):
            if node is None:
                return
            dfs(node.left)
            self.vals.append(node.val)
            dfs(node.right)
        dfs(root)
        self.i = 0
    def next(self):
        v = self.vals[self.i]
        self.i += 1
        return v
    def hasNext(self):
        return self.i < len(self.vals)

